SELECT o.*, s.name FROM orders o JOIN strategies s ON s.id=o.strategy_id WHERE s.name IN ('risk_neutral','aggressive') AND ((o.execution_venue='PAPER' AND o.account_scope=%(account_scope)s) OR o.execution_venue='UNKNOWN') AND o.created_at <= %(cutoff)s ORDER BY o.created_at;
SELECT e.* FROM executions e JOIN orders o ON o.id=e.order_id JOIN strategies s ON s.id=o.strategy_id WHERE s.name IN ('risk_neutral','aggressive') AND ((o.execution_venue='PAPER' AND o.account_scope=%(account_scope)s) OR o.execution_venue='UNKNOWN') AND e.executed_at <= %(cutoff)s ORDER BY e.executed_at;
SELECT bh.* FROM balance_history bh JOIN strategies s ON s.id=bh.strategy_id WHERE s.name IN ('risk_neutral','aggressive') AND ((bh.execution_venue='PAPER' AND bh.account_scope=%(account_scope)s) OR bh.execution_venue='UNKNOWN') AND bh.recorded_at <= %(cutoff)s ORDER BY bh.recorded_at;

